def verify(subject: str, predicate: str, obj: str) -> bool:
    """
    Verify if a year is a leap year.
    Leap year rules: divisible by 4, except for years divisible by 100,
    except for years divisible by 400.
    """
    if predicate != 'is_leap_year':
        return False

    try:
        year = int(subject)
    except ValueError:
        return False

    # Determine if year is a leap year
    is_leap = False
    if year % 400 == 0:
        is_leap = True
    elif year % 100 == 0:
        is_leap = False
    elif year % 4 == 0:
        is_leap = True

    # Check if the result matches the expected object value
    expected = obj.lower() == 'true'
    return is_leap == expected

