        return False

    try:
        n = int(subject)
    except ValueError:
        return False

    # A prime number must be greater than 1
    if n < 2:
        return False

    # Check for divisibility from 2 to sqrt(n)
    if n == 2:
        return obj.lower() == 'true'

    if n % 2 == 0:
        return obj.lower() == 'false'

    i = 3
    while i * i <= n:
